def create_saml_request():
    # Create a new SAML authentication request
    saml_request = ET.Element('samlp:AuthnRequest', xmlns='urn:oasis:names:tc:SAML:2.0:protocol', 
                              AssertionConsumerServiceURL=url_for('saml_acs', _external=True))
